else
    _xor=function(a,b)
        local r,p=0,1
        for i=0,7 do
            local a1,b1=a%2,b%2
            if a1~=b1 then r=r+p end
            a,b,p=math.floor(a/2),math.floor(b/2),p*2
        end
        return r
    end
end

